rule.specification:
案例代码：
entity entitymodulename_top is
port (
	zhenwvml_outputport : out STD_LOGIC     //输出端口和实体名字符长度不应超过16
);
end entity;

案例代码：
library IEEE;
use IEEE.std_logic_1164.all;
entity ENCODER is
  port (
		A : in std_logic_vector(7 downto 0);
		Y : out std_logic_vector(2 downto 0));
end ENCODER;
architecture RTL of ENCODER is
begin
 process (A) begin
  case A is
	when "01111111" => Y <= "000";
	when "10111111" => Y <= "001";
	when "11011111" => Y <= "010";
	when "11101111" => Y <= "011";
	when "11110111" => Y <= "100";
	when "11111011" => Y <= "101";
	when "11111101" => Y <= "110";
	when "11111110" => Y <= "111";
	when others => Y <= "XXX";    //使用‘X’赋值可减小电路面积，但会生成包含未知值的电路，应避免这种给航天器产品造成危险的行为。
   end case;
 end process;

案例代码：
library ieee;
use ieee.std_logic_1164.all;
use ieee.std_logic_arith.all;
entity add_s is
port (
	arg_a: in unsigned;
	arg_b: in signed;
	y_out: out std_logic_vector
);
end entity add_s;
architecture rtl of add_s is
begin
	y_out <= arg_a + arg_b;        //混用了符号操作数和无符号操作数
end architecture rtl;

案例代码：
process begin //包含基于wait 语句描述的触发器。触发器描述应限制为if 语句。
	wait until rising_edge(clk);
	Q <= data;
	if (sync_set = '1') then
		Q <= '1';
	end if;
end process;

案例代码：
entity top is
port (
CLK, CTRL, D1, D2: in std_logic;
OUT1 : out std_logic;
OUT2 : out std_logic
);
end entity;

architecture basic of top is
signal and_clk : std_logic;
begin
	DFF1 : entity dff port map ( CLK => and_clk, D => D1, Q => OUT1 );
	DFF2 : entity dff port map ( CLK => CLK, D => D2, Q => OUT2 );
	and_clk <= CTRL and CLK;		//全局时钟“CLK”通过了门控，只要有可能就不要将门控时钟用在FPGA中，因为这样的设计进行时钟延迟和偏斜的细调会变得很困难
end architecture;

案例代码：  
entity FSM is
port (
	READY : out STD_LOGIC
);
end entity;

architecture RTL of FSM is
constant READY_EN : boolean := true;
begin
	READY <= '1' when READY_EN else '0';        //固定值被连接到了输出端口“READY”，可能导致一致性比较的问题
end architecture;

案例代码：
entity DFF is		//实体“DFF”没有使用IEEE.std_logic_1164,RTL设计需要通过连接基本包来使用std_logic和std_logic_vector
	...
end DFF;
library ieee;
use ieee.std_logic_1164.all;
architecture RTL of DFF is
	...
end RTL;

案例代码：
component MUX2x1 is		//一个非标准逻辑类型用于端口定义，端口应该是std_logic和std_logic_vector类型
port(
	d1: in std_logic_vector;
	d2: in std_logic_vector;
	sel: in bit;		//端口“sel”是一个非标准逻辑类型
	mout: out std_logic_vector
	);
end component;

案例代码：
library synopsys;
use synopsys.attributes.all;
attribute ENUM_ENCODING of my_enc : type is "001 010 100";		//不要在RTL描述中使用属性enum_encoding

案例代码：
process (CLK)
variable B : std_logic;
begin
if(CLK'event and CLK='1') then
 B := A;
 C <= B; //使用变量赋值
end if;
end process;

案例代码：
process (Data_in, Data_accum) is       //在进程中发现对同一个信号的赋值和引用。这种代码的仿真效率很低且可读性较差
begin
	temp <= Data_in;
	Q <= Data_accum + temp;        //信号temp 在进程中被赋值和引用
end process;

案例代码：
architecture Behavioral of top is
   component add_rst
	  port( 
		clk             :in  std_logic;
		rst_1            :in  std_logic; 
		rst_2            :in  std_logic;		  
		rst_o            :out std_logic
	   );
  end component;
begin
 r1: add_rst PORT MAP(clk,rst_1,rst_2,rst_o);		//端口连接应通过名字描述连接
end Behavioral;
